        if (photoUrl && photoUrl.startsWith("data:image")) {
          try {
            doc.addImage(photoUrl, "JPEG", M+i*(pW+6)+2, y+2, pW-4, pH-10);
          } catch (e) {
            console.error("[PDF photo]", e);
          }
        }
        doc.setFillColor(0,0,0); doc.rect(M+i*(pW+6),y+pH-8,pW,8,"F");
